#!/usr/bin/env python3
"""Generate Python TypedDicts from the JSON Schema artifact.

Source: packages/timeline-schema/python/banodoco_timeline_schema/timeline.schema.json
Target: packages/timeline-schema/python/banodoco_timeline_schema/generated.py
"""

from __future__ import annotations

import subprocess
import sys
from pathlib import Path

PKG_ROOT = Path(__file__).resolve().parent.parent
SCHEMA = PKG_ROOT / "python" / "banodoco_timeline_schema" / "timeline.schema.json"
OUT = PKG_ROOT / "python" / "banodoco_timeline_schema" / "generated.py"

HEADER = "# AUTO-GENERATED by scripts/gen_python_types.py — do not edit by hand.\n"


def main() -> int:
    if not SCHEMA.is_file():
        print(f"missing JSON Schema artifact at {SCHEMA}; run `npm run build` first", file=sys.stderr)
        return 1
    cmd = [
        sys.executable, "-m", "datamodel_code_generator",
        "--input", str(SCHEMA),
        "--input-file-type", "jsonschema",
        "--output", str(OUT),
        "--output-model-type", "typing.TypedDict",
        "--target-python-version", "3.10",
        "--use-schema-description",
        "--disable-timestamp",
        "--use-double-quotes",
        "--collapse-root-models",
    ]
    result = subprocess.run(cmd, check=False)
    if result.returncode != 0:
        return result.returncode
    body = OUT.read_text(encoding="utf-8")
    if not body.startswith("# AUTO-GENERATED"):
        OUT.write_text(HEADER + body, encoding="utf-8")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
